def solve(nums: Array[Long]): Long = {
   val A = nums.map(Math.abs).sorted
   var count = 0L
   for (i <- 0 until A.length - 1) {
      val target = 2 * A(i)
      var low = i + 1
      var high = A.length - 1
      var res = i
      while (low <= high) {
         val mid = (low + high) / 2
         if (A(mid) <= target) {
            res = mid
            low = mid + 1
         } else {
            high = mid - 1
         }
      }
      count += res - i
   }
   count
}
